    INSERT INTO [Vocabularies] (Word, Meaning, Pronunciation, PartOfSpeech, CEFRLevel, Description, ExampleSentence, ImageUrl, PronunciationUrl) VALUES (N'Apple', N'quả táo', N'/ˈæp.əl/', 0, 0, N'A common, round fruit produced by the tree Malus domestica, cultivated in temperate climates.', NULL, N'https://images.unsplash.com/photo-1568702846914-96b305d2aaeb?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w4ODc0MDN8MHwxfHNlYXJjaHwxfHxhcHBsZXxlbnwwfDB8fHwxNzcyNjI1MTc5fDA&ixlib=rb-4.1.0&q=80&w=1080', N'https://api.dictionaryapi.dev/media/pronunciations/en/apple-uk.mp3');
    INSERT INTO [Vocabularies] (Word, Meaning, Pronunciation, PartOfSpeech, CEFRLevel, Description, ExampleSentence, ImageUrl, PronunciationUrl) VALUES (N'Book', N'sách', N'/buːk/', 0, 0, N'A collection of sheets of paper bound together to hinge at one edge, containing printed or written material, pictures, etc.', N'He was frustrated because he couldn''t find anything about dinosaurs in the book.', N'https://images.unsplash.com/photo-1457369804613-52c61a468e7d?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w4ODc0MDN8MHwxfHNlYXJjaHwxfHxib29rfGVufDB8MHx8fDE3NzI2MjUxODR8MA&ixlib=rb-4.1.0&q=80&w=1080', N'https://api.dictionaryapi.dev/media/pronunciations/en/book-uk.mp3');
    INSERT INTO [Vocabularies] (Word, Meaning, Pronunciation, PartOfSpeech, CEFRLevel, Description, ExampleSentence, ImageUrl, PronunciationUrl) VALUES (N'Cat', N'con mèo', N'/kat/', 0, 0, N'An animal of the family Felidae:', NULL, N'https://images.unsplash.com/photo-1514888286974-6c03e2ca1dba?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w4ODc0MDN8MHwxfHNlYXJjaHwxfHxjYXR8ZW58MHwwfHx8MTc3MjYyNTE4OHww&ixlib=rb-4.1.0&q=80&w=1080', N'https://api.dictionaryapi.dev/media/pronunciations/en/cat-uk.mp3');
    INSERT INTO [Vocabularies] (Word, Meaning, Pronunciation, PartOfSpeech, CEFRLevel, Description, ExampleSentence, ImageUrl, PronunciationUrl) VALUES (N'Dog', N'chó', N'/dɑɡ/', 0, 0, N'A mammal, Canis familiaris or Canis lupus familiaris, that has been domesticated for thousands of years, of highly variable appearance due to human breeding.', N'The dog barked all night long.', N'https://images.unsplash.com/photo-1561037404-61cd46aa615b?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w4ODc0MDN8MHwxfHNlYXJjaHwxfHxkb2d8ZW58MHwwfHx8MTc3MjYyNTE5Mnww&ixlib=rb-4.1.0&q=80&w=1080', N'https://api.dictionaryapi.dev/media/pronunciations/en/dog-uk.mp3');
    INSERT INTO [Vocabularies] (Word, Meaning, Pronunciation, PartOfSpeech, CEFRLevel, Description, ExampleSentence, ImageUrl, PronunciationUrl) VALUES (N'Eat', N'ăn', N'/iːt/', 0, 0, N'Something to be eaten; a meal; a food item.', NULL, N'https://images.unsplash.com/photo-1565895405138-6c3a1555da6a?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w4ODc0MDN8MHwxfHNlYXJjaHwxfHxlYXR8ZW58MHwwfHx8MTc3MjYyNTE5Nnww&ixlib=rb-4.1.0&q=80&w=1080', N'https://api.dictionaryapi.dev/media/pronunciations/en/eat-uk.mp3');
    INSERT INTO [Vocabularies] (Word, Meaning, Pronunciation, PartOfSpeech, CEFRLevel, Description, ExampleSentence, ImageUrl, PronunciationUrl) VALUES (N'Fish', N'cá', N'/fɪʃ/', 0, 0, N'A cold-blooded vertebrate animal that lives in water, moving with the help of fins and breathing with gills.', N'Salmon is a fish.', N'https://images.unsplash.com/photo-1578507065211-1c4e99a5fd24?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w4ODc0MDN8MHwxfHNlYXJjaHwxfHxmaXNofGVufDB8MHx8fDE3NzI2MjUxOTl8MA&ixlib=rb-4.1.0&q=80&w=1080', N'https://api.dictionaryapi.dev/media/pronunciations/en/fish-au.mp3');
    INSERT INTO [Vocabularies] (Word, Meaning, Pronunciation, PartOfSpeech, CEFRLevel, Description, ExampleSentence, ImageUrl, PronunciationUrl) VALUES (N'Good', N'Tốt', N'/ɡʊ(d)/', 2, 0, N'(of people)', NULL, N'https://images.unsplash.com/photo-1604367285486-763bed037bd7?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w4ODc0MDN8MHwxfHNlYXJjaHwxfHxnb29kfGVufDB8MHx8fDE3NzI2MjUyMDN8MA&ixlib=rb-4.1.0&q=80&w=1080', N'https://api.dictionaryapi.dev/media/pronunciations/en/good-uk.mp3');
    INSERT INTO [Vocabularies] (Word, Meaning, Pronunciation, PartOfSpeech, CEFRLevel, Description, ExampleSentence, ImageUrl, PronunciationUrl) VALUES (N'House', N'căn nhà', N'/hʌʊs/', 0, 0, N'A structure built or serving as an abode of human beings.', N'This is my house and my family''s ancestral home.', N'https://images.unsplash.com/photo-1570129477492-45c003edd2be?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w4ODc0MDN8MHwxfHNlYXJjaHwxfHxob3VzZXxlbnwwfDB8fHwxNzcyNjI1MjA2fDA&ixlib=rb-4.1.0&q=80&w=1080', N'https://api.dictionaryapi.dev/media/pronunciations/en/house-1-ca.mp3');
    INSERT INTO [Vocabularies] (Word, Meaning, Pronunciation, PartOfSpeech, CEFRLevel, Description, ExampleSentence, ImageUrl, PronunciationUrl) VALUES (N'Idea', N'ý tưởng', N'/ɑeˈdiə̯/', 0, 0, N'An abstract archetype of a given thing, compared to which real-life examples are seen as imperfect approximations; pure essence, as opposed to actual examples.', NULL, N'https://images.unsplash.com/photo-1512314889357-e157c22f938d?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w4ODc0MDN8MHwxfHNlYXJjaHwxfHxpZGVhfGVufDB8MHx8fDE3NzI2MjUyMTF8MA&ixlib=rb-4.1.0&q=80&w=1080', N'https://api.dictionaryapi.dev/media/pronunciations/en/idea-us.mp3');
    INSERT INTO [Vocabularies] (Word, Meaning, Pronunciation, PartOfSpeech, CEFRLevel, Description, ExampleSentence, ImageUrl, PronunciationUrl) VALUES (N'Jump', N'nhảy', N'/dʒʌmp/', 0, 0, N'The act of jumping; a leap; a spring; a bound.', NULL, N'https://images.unsplash.com/photo-1520371764250-8213f40bc3ed?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w4ODc0MDN8MHwxfHNlYXJjaHwxfHxqdW1wfGVufDB8MHx8fDE3NzI2MjUyMTR8MA&ixlib=rb-4.1.0&q=80&w=1080', N'https://api.dictionaryapi.dev/media/pronunciations/en/jump-us.mp3');
    INSERT INTO [Vocabularies] (Word, Meaning, Pronunciation, PartOfSpeech, CEFRLevel, Description, ExampleSentence, ImageUrl, PronunciationUrl) VALUES (N'Key', N'chìa khóa', N'/kiː/', 0, 0, N'An object designed to open and close a lock.', NULL, N'https://images.unsplash.com/flagged/photo-1564767609342-620cb19b2357?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w4ODc0MDN8MHwxfHNlYXJjaHwxfHxrZXl8ZW58MHwwfHx8MTc3MjYyNTIxOHww&ixlib=rb-4.1.0&q=80&w=1080', N'https://api.dictionaryapi.dev/media/pronunciations/en/key-uk.mp3');
    INSERT INTO [Vocabularies] (Word, Meaning, Pronunciation, PartOfSpeech, CEFRLevel, Description, ExampleSentence, ImageUrl, PronunciationUrl) VALUES (N'Love', N'yêu', N'/lʊv/', 0, 0, N'Strong affection.', NULL, N'https://images.unsplash.com/reserve/Af0sF2OS5S5gatqrKzVP_Silhoutte.jpg?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w4ODc0MDN8MHwxfHNlYXJjaHwxfHxsb3ZlfGVufDB8MHx8fDE3NzI2MjUyMjF8MA&ixlib=rb-4.1.0&q=80&w=1080', N'https://api.dictionaryapi.dev/media/pronunciations/en/love-uk.mp3');
    INSERT INTO [Vocabularies] (Word, Meaning, Pronunciation, PartOfSpeech, CEFRLevel, Description, ExampleSentence, ImageUrl, PronunciationUrl) VALUES (N'Milk', N'sữa', N'[mɛlk]', 0, 0, N'A white liquid produced by the mammary glands of female mammals to nourish their young. From certain animals, especially cows, it is also called dairy milk and is a common food for humans as a beverage or used to produce various dairy products such as butter, cheese, and yogurt.', NULL, N'https://images.unsplash.com/photo-1637382752225-d7f97e1ddd03?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w4ODc0MDN8MHwxfHNlYXJjaHwxfHxtaWxrfGVufDB8MHx8fDE3NzI2MjUyMjZ8MA&ixlib=rb-4.1.0&q=80&w=1080', N'https://api.dictionaryapi.dev/media/pronunciations/en/milk-uk.mp3');
    INSERT INTO [Vocabularies] (Word, Meaning, Pronunciation, PartOfSpeech, CEFRLevel, Description, ExampleSentence, ImageUrl, PronunciationUrl) VALUES (N'Name', N'tên', N'/neɪm/', 0, 0, N'Any nounal word or phrase which indicates a particular person, place, class, or thing.', N'I''ve never liked the name my parents gave me so I changed it at the age of twenty.', N'https://images.unsplash.com/photo-1605402756180-75934835ce13?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w4ODc0MDN8MHwxfHNlYXJjaHwxfHxuYW1lfGVufDB8MHx8fDE3NzI2MjUyMzB8MA&ixlib=rb-4.1.0&q=80&w=1080', N'https://api.dictionaryapi.dev/media/pronunciations/en/name-1-au.mp3');
    INSERT INTO [Vocabularies] (Word, Meaning, Pronunciation, PartOfSpeech, CEFRLevel, Description, ExampleSentence, ImageUrl, PronunciationUrl) VALUES (N'Open', N'mở', N'/ˈəʊ.pən/', 2, 0, N'Not closed', NULL, N'https://images.unsplash.com/photo-1599595344070-c456bea6ee98?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w4ODc0MDN8MHwxfHNlYXJjaHwxfHxvcGVufGVufDB8MHx8fDE3NzI2MjUyMzN8MA&ixlib=rb-4.1.0&q=80&w=1080', N'https://api.dictionaryapi.dev/media/pronunciations/en/open-au.mp3');
    INSERT INTO [Vocabularies] (Word, Meaning, Pronunciation, PartOfSpeech, CEFRLevel, Description, ExampleSentence, ImageUrl, PronunciationUrl) VALUES (N'Play', N'chơi', N'/pleɪ/', 0, 0, N'Activity for amusement only, especially among the young.', N'Children learn through play.', N'https://images.unsplash.com/photo-1502086223501-7ea6ecd79368?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w4ODc0MDN8MHwxfHNlYXJjaHwxfHxwbGF5fGVufDB8MHx8fDE3NzI2MjUyMzd8MA&ixlib=rb-4.1.0&q=80&w=1080', N'https://api.dictionaryapi.dev/media/pronunciations/en/play-us.mp3');
    INSERT INTO [Vocabularies] (Word, Meaning, Pronunciation, PartOfSpeech, CEFRLevel, Description, ExampleSentence, ImageUrl, PronunciationUrl) VALUES (N'Read', N'đọc', N'/ɹiːd/', 0, 0, N'A reading or an act of reading, especially an actor''s part of a play.', NULL, N'https://images.unsplash.com/photo-1491309055486-24ae511c15c7?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w4ODc0MDN8MHwxfHNlYXJjaHwxfHxyZWFkfGVufDB8MHx8fDE3NzI2MjUyNDF8MA&ixlib=rb-4.1.0&q=80&w=1080', N'https://api.dictionaryapi.dev/media/pronunciations/en/read-1-uk.mp3');
    INSERT INTO [Vocabularies] (Word, Meaning, Pronunciation, PartOfSpeech, CEFRLevel, Description, ExampleSentence, ImageUrl, PronunciationUrl) VALUES (N'Run', N'chạy', N'/ɹʊn/', 1, 0, N'To run.', NULL, N'https://images.unsplash.com/photo-1502224562085-639556652f33?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w4ODc0MDN8MHwxfHNlYXJjaHwxfHxydW58ZW58MHwwfHx8MTc3MjYyNTI0NXww&ixlib=rb-4.1.0&q=80&w=1080', N'https://api.dictionaryapi.dev/media/pronunciations/en/run-au.mp3');
    INSERT INTO [Vocabularies] (Word, Meaning, Pronunciation, PartOfSpeech, CEFRLevel, Description, ExampleSentence, ImageUrl, PronunciationUrl) VALUES (N'Sit', N'ngồi', N'/sɪt/', 0, 0, N'Subsidence of the roof of a coal mine.', NULL, N'https://images.unsplash.com/photo-1502325966718-85a90488dc29?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w4ODc0MDN8MHwxfHNlYXJjaHwxfHxzaXR8ZW58MHwwfHx8MTc3MjYyNTI0OXww&ixlib=rb-4.1.0&q=80&w=1080', N'https://api.dictionaryapi.dev/media/pronunciations/en/sit-au.mp3');
    INSERT INTO [Vocabularies] (Word, Meaning, Pronunciation, PartOfSpeech, CEFRLevel, Description, ExampleSentence, ImageUrl, PronunciationUrl) VALUES (N'Talk', N'nói chuyện', N'/toːk/', 1, 0, N'To communicate, usually by means of speech.', N'Although I don''t speak Chinese I managed to talk with the villagers using signs and gestures.', N'https://images.unsplash.com/photo-1577563908411-5077b6dc7624?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w4ODc0MDN8MHwxfHNlYXJjaHwxfHx0YWxrfGVufDB8MHx8fDE3NzI2MjUyNTN8MA&ixlib=rb-4.1.0&q=80&w=1080', NULL);
    INSERT INTO [Vocabularies] (Word, Meaning, Pronunciation, PartOfSpeech, CEFRLevel, Description, ExampleSentence, ImageUrl, PronunciationUrl) VALUES (N'Use', N'sử dụng', NULL, 0, 0, N'The act of using.', N'The use of torture has been condemned by the United Nations.', N'https://images.unsplash.com/photo-1617348016197-bd031e297ce3?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w4ODc0MDN8MHwxfHNlYXJjaHwxfHx1c2V8ZW58MHwwfHx8MTc3MjYyNTI1N3ww&ixlib=rb-4.1.0&q=80&w=1080', NULL);
    INSERT INTO [Vocabularies] (Word, Meaning, Pronunciation, PartOfSpeech, CEFRLevel, Description, ExampleSentence, ImageUrl, PronunciationUrl) VALUES (N'Walk', N'đi bộ', N'/wɔːk/', 1, 0, N'To move on the feet by alternately setting each foot (or pair or group of feet, in the case of animals with four or more feet) forward, with at least one foot on the ground at all times. Compare run.', N'To walk briskly for an hour every day is to keep fit.', N'https://images.unsplash.com/photo-1487956382158-bb926046304a?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w4ODc0MDN8MHwxfHNlYXJjaHwxfHx3YWxrfGVufDB8MHx8fDE3NzI2MjUyNjJ8MA&ixlib=rb-4.1.0&q=80&w=1080', N'https://api.dictionaryapi.dev/media/pronunciations/en/walk-au.mp3');
    INSERT INTO [Vocabularies] (Word, Meaning, Pronunciation, PartOfSpeech, CEFRLevel, Description, ExampleSentence, ImageUrl, PronunciationUrl) VALUES (N'Year', N'năm', N'/jɪə/', 0, 0, N'A solar year, the time it takes the Earth to complete one revolution of the Sun (between 365.24 and 365.26 days depending on the point of reference).', N'we moved to this town a year ago;  I quit smoking exactly one year ago', N'https://images.unsplash.com/photo-1542176107-f50284e217c5?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w4ODc0MDN8MHwxfHNlYXJjaHwxfHx5ZWFyfGVufDB8MHx8fDE3NzI2MjUyNjd8MA&ixlib=rb-4.1.0&q=80&w=1080', N'https://api.dictionaryapi.dev/media/pronunciations/en/year-1-uk.mp3');
    INSERT INTO [Vocabularies] (Word, Meaning, Pronunciation, PartOfSpeech, CEFRLevel, Description, ExampleSentence, ImageUrl, PronunciationUrl) VALUES (N'Zero', N'không', N'/ˈzɪəɹəʊ/', 0, 0, N'The numeric symbol that represents the cardinal number zero.', N'In unary and k-adic notation in general, zero is the empty string.', N'https://images.unsplash.com/photo-1608094921359-6a7a5d414fc6?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w4ODc0MDN8MHwxfHNlYXJjaHwxfHx6ZXJvfGVufDB8MHx8fDE3NzI2MjUyNzF8MA&ixlib=rb-4.1.0&q=80&w=1080', N'https://api.dictionaryapi.dev/media/pronunciations/en/zero-au.mp3');
    INSERT INTO [Vocabularies] (Word, Meaning, Pronunciation, PartOfSpeech, CEFRLevel, Description, ExampleSentence, ImageUrl, PronunciationUrl) VALUES (N'Baby', N'Đứa bé', N'/ˈbeɪbi/', 0, 0, N'A very young human, particularly from birth to a couple of years old or until walking is fully mastered.', NULL, N'https://images.unsplash.com/photo-1510154221590-ff63e90a136f?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w4ODc0MDN8MHwxfHNlYXJjaHwxfHxiYWJ5fGVufDB8MHx8fDE3NzI2MjUyNzd8MA&ixlib=rb-4.1.0&q=80&w=1080', N'https://api.dictionaryapi.dev/media/pronunciations/en/baby-uk.mp3');
    INSERT INTO [Vocabularies] (Word, Meaning, Pronunciation, PartOfSpeech, CEFRLevel, Description, ExampleSentence, ImageUrl, PronunciationUrl) VALUES (N'Card', N'thẻ', N'/kaːd/', 0, 0, N'A playing card.', NULL, N'https://images.unsplash.com/photo-1613243555988-441166d4d6fd?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w4ODc0MDN8MHwxfHNlYXJjaHwxfHxjYXJkfGVufDB8MHx8fDE3NzI2MjUyODB8MA&ixlib=rb-4.1.0&q=80&w=1080', N'https://api.dictionaryapi.dev/media/pronunciations/en/card-au.mp3');
    INSERT INTO [Vocabularies] (Word, Meaning, Pronunciation, PartOfSpeech, CEFRLevel, Description, ExampleSentence, ImageUrl, PronunciationUrl) VALUES (N'Door', N'cửa', N'/dɔː/', 0, 0, N'A portal of entry into a building, room, or vehicle, consisting of a rigid plane movable on a hinge. Doors are frequently made of wood or metal. May have a handle to help open and close, a latch to hold the door closed and a lock that ensures the door cannot be opened without the key.', N'I knocked on the vice president''s door', N'https://images.unsplash.com/photo-1552819401-700b5e342b9d?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w4ODc0MDN8MHwxfHNlYXJjaHwxfHxkb29yfGVufDB8MHx8fDE3NzI2MjUyODR8MA&ixlib=rb-4.1.0&q=80&w=1080', N'https://api.dictionaryapi.dev/media/pronunciations/en/door-uk.mp3');
    INSERT INTO [Vocabularies] (Word, Meaning, Pronunciation, PartOfSpeech, CEFRLevel, Description, ExampleSentence, ImageUrl, PronunciationUrl) VALUES (N'Food', N'đồ ăn', N'/fuːd/', 0, 0, N'Any solid substance that can be consumed by living organisms, especially by eating, in order to sustain life.', N'The innkeeper brought them food and drink.', N'https://images.unsplash.com/photo-1504674900247-0877df9cc836?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w4ODc0MDN8MHwxfHNlYXJjaHwxfHxmb29kfGVufDB8MHx8fDE3NzI2MjUyODl8MA&ixlib=rb-4.1.0&q=80&w=1080', N'https://api.dictionaryapi.dev/media/pronunciations/en/food-uk.mp3');
    INSERT INTO [Vocabularies] (Word, Meaning, Pronunciation, PartOfSpeech, CEFRLevel, Description, ExampleSentence, ImageUrl, PronunciationUrl) VALUES (N'Give', N'đưa cho', N'/ɡɪv/', 0, 0, N'The amount of bending that something undergoes when a force is applied to it; a tendency to yield under pressure; resilence.', N'There is no give in his dogmatic religious beliefs.', N'https://images.unsplash.com/photo-1579208575657-c595a05383b7?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w4ODc0MDN8MHwxfHNlYXJjaHwxfHxnaXZlfGVufDB8MHx8fDE3NzI2MjUyOTN8MA&ixlib=rb-4.1.0&q=80&w=1080', N'https://api.dictionaryapi.dev/media/pronunciations/en/give-1-uk.mp3');
    INSERT INTO [Vocabularies] (Word, Meaning, Pronunciation, PartOfSpeech, CEFRLevel, Description, ExampleSentence, ImageUrl, PronunciationUrl) VALUES (N'Hand', N'tay', N'/hænd/', 0, 0, N'The part of the forelimb below the forearm or wrist in a human, and the corresponding part in many other animals.', N'Her hands are really strong.', N'https://images.unsplash.com/photo-1586726370832-3440a511e479?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w4ODc0MDN8MHwxfHNlYXJjaHwxfHxoYW5kfGVufDB8MHx8fDE3NzI2MjUyOTh8MA&ixlib=rb-4.1.0&q=80&w=1080', N'https://api.dictionaryapi.dev/media/pronunciations/en/hand-uk.mp3');
    INSERT INTO [Vocabularies] (Word, Meaning, Pronunciation, PartOfSpeech, CEFRLevel, Description, ExampleSentence, ImageUrl, PronunciationUrl) VALUES (N'Call', N'gọi', N'/kɔːɫ/', 0, 0, N'A telephone conversation.', N'I received several calls today.', N'https://images.unsplash.com/photo-1512428559087-560fa5ceab42?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w4ODc0MDN8MHwxfHNlYXJjaHwxfHxjYWxsfGVufDB8MHx8fDE3NzI2MjU2NDZ8MA&ixlib=rb-4.1.0&q=80&w=1080', N'https://api.dictionaryapi.dev/media/pronunciations/en/call-au.mp3');
    INSERT INTO [Vocabularies] (Word, Meaning, Pronunciation, PartOfSpeech, CEFRLevel, Description, ExampleSentence, ImageUrl, PronunciationUrl) VALUES (N'Come', N'đến', N'/kʌm/', 0, 0, N'Coming, arrival; approach.', NULL, N'https://images.unsplash.com/photo-1686930510940-b26b5fe4aec1?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w4ODc0MDN8MHwxfHNlYXJjaHwxfHxjb21lfGVufDB8MHx8fDE3NzI2MjU2NDl8MA&ixlib=rb-4.1.0&q=80&w=1080', N'https://api.dictionaryapi.dev/media/pronunciations/en/come-1-uk.mp3');
    INSERT INTO [Vocabularies] (Word, Meaning, Pronunciation, PartOfSpeech, CEFRLevel, Description, ExampleSentence, ImageUrl, PronunciationUrl) VALUES (N'Day', N'ngày', N'/deɪ/', 0, 0, N'Any period of 24 hours.', N'I''ve been here for two days and a bit.', N'https://images.unsplash.com/photo-1542709111240-e9df0dd813b4?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w4ODc0MDN8MHwxfHNlYXJjaHwxfHxkYXl8ZW58MHwwfHx8MTc3MjYyNTY1NHww&ixlib=rb-4.1.0&q=80&w=1080', N'https://api.dictionaryapi.dev/media/pronunciations/en/day-us.mp3');
